generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
  url      = env("DATABASE_URL")
}

model Post {
  id        Int      @id @default(autoincrement())
  title     String
  content   String
  createdAt DateTime @default(now())
}

/**
 * Server-only database module.
 *
 * This file MUST never be imported from client-reachable code. It is only
 * imported from `routeLoader$`, `routeAction$` and `server$` callbacks, which
 * Qwik guarantees run exclusively on the server and are stripped from the
 * client build.
 *
 * The `.server.ts` extension is a convention that helps tooling recognize this
 * boundary, but the real protection comes from only using it inside server
 * functions.
 */
import { PrismaClient } from "@prisma/client";

// Reuse a single client across hot-reloads in dev to avoid exhausting
// SQLite connections.
const globalForPrisma = globalThis as unknown as {
  prisma?: PrismaClient;
};

export const prisma =
  globalForPrisma.prisma ??
  new PrismaClient({
    log: ["error", "warn"],
  });

if (process.env.NODE_ENV !== "production") {
  globalForPrisma.prisma = prisma;
}

/**
 * Seed script. Run with: `node --experimental-strip-types prisma/seed.ts`
 * or via the `prisma db seed` command (configured in package.json).
 */
import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

const posts = [
  {
    title: "Welcome to Qwik",
    content:
      "Qwik delivers instant-loading web applications through resumability.",
  },
  {
    title: "Understanding Resumability",
    content:
      "Resumability lets the app pause on the server and resume on the client without hydration.",
  },
  {
    title: "Server-Side Data with routeLoader",
    content:
      "routeLoader fetches data on the server before rendering the route.",
  },
];

async function main() {
  // Reset so seeding is idempotent and ids stay 1, 2, 3.
  await prisma.post.deleteMany();

  for (const post of posts) {
    await prisma.post.create({ data: post });
  }

  const all = await prisma.post.findMany({ orderBy: { id: "asc" } });
  console.log("Seeded posts:", all);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

