import path from "node:path";
import "dotenv/config";
import { defineConfig } from "prisma/config";

/**
 * Resolve the SQLite file location.
 *
 * The Prisma default `DATABASE_URL="file:./dev.db"` historically resolved
 * relative to the Prisma schema directory (`prisma/`), producing
 * `prisma/dev.db`. In Prisma ORM v7 the connection URL is resolved relative to
 * the current working directory instead, so we normalize it back to an
 * absolute path under `prisma/` to keep the database file in the expected
 * location regardless of where the CLI is invoked from.
 */
function resolveDbFile(): string {
  const url = process.env.DATABASE_URL ?? "file:./dev.db";
  const relativePath = url.replace(/^file:/, "");
  return path.resolve(process.cwd(), "prisma", relativePath);
}

export default defineConfig({
  schema: "prisma/schema.prisma",
  migrations: {
    path: "prisma/migrations",
    seed: "node --experimental-strip-types prisma/seed.ts",
  },
  datasource: {
    url: `file:${resolveDbFile()}`,
  },
});

/**
 * Server-only database module.
 *
 * This file MUST never be imported from client-reachable code. It is only
 * imported from `routeLoader$`, `routeAction$` and `server$` callbacks, which
 * Qwik guarantees run exclusively on the server and are stripped from the
 * client build.
 *
 * The `.server.ts` extension is a convention that helps tooling recognize this
 * boundary, but the real protection comes from only using it inside server
 * functions.
 */
import path from "node:path";
import { PrismaClient } from "@prisma/client";
import { PrismaBetterSqlite3 } from "@prisma/adapter-better-sqlite3";

/**
 * Resolve the SQLite file location.
 *
 * The Prisma default `DATABASE_URL="file:./dev.db"` resolves to
 * `prisma/dev.db` (relative to the project's `prisma/` directory), matching
 * the Prisma CLI behavior configured in `prisma.config.ts`.
 */
function resolveDbFile(): string {
  const url = process.env.DATABASE_URL ?? "file:./dev.db";
  const relativePath = url.replace(/^file:/, "");
  return path.resolve(process.cwd(), "prisma", relativePath);
}

function createPrismaClient(): PrismaClient {
  const adapter = new PrismaBetterSqlite3({
    url: `file:${resolveDbFile()}`,
  });
  return new PrismaClient({ adapter });
}

// Reuse a single client across hot-reloads in dev to avoid exhausting
// SQLite connections.
const globalForPrisma = globalThis as unknown as {
  prisma?: PrismaClient;
};

export const prisma: PrismaClient =
  globalForPrisma.prisma ?? createPrismaClient();

if (process.env.NODE_ENV !== "production") {
  globalForPrisma.prisma = prisma;
}

/**
 * Seed script. Run with: `prisma db seed` (configured in prisma.config.ts).
 */
import path from "node:path";
import "dotenv/config";
import { PrismaClient } from "@prisma/client";
import { PrismaBetterSqlite3 } from "@prisma/adapter-better-sqlite3";

function resolveDbFile(): string {
  const url = process.env.DATABASE_URL ?? "file:./dev.db";
  const relativePath = url.replace(/^file:/, "");
  return path.resolve(process.cwd(), "prisma", relativePath);
}

const prisma = new PrismaClient({
  adapter: new PrismaBetterSqlite3({ url: `file:${resolveDbFile()}` }),
});

const posts = [
  {
    title: "Welcome to Qwik",
    content:
      "Qwik delivers instant-loading web applications through resumability.",
  },
  {
    title: "Understanding Resumability",
    content:
      "Resumability lets the app pause on the server and resume on the client without hydration.",
  },
  {
    title: "Server-Side Data with routeLoader",
    content:
      "routeLoader fetches data on the server before rendering the route.",
  },
];

async function main() {
  // Reset so seeding is idempotent and ids stay 1, 2, 3.
  await prisma.post.deleteMany();

  for (const post of posts) {
    await prisma.post.create({ data: post });
  }

  const all = await prisma.post.findMany({ orderBy: { id: "asc" } });
  console.log("Seeded posts:", all);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

